example.code:
# Fake: implements the interface, simpler to maintain
class InMemoryUserRepository:
    def __init__(self):
        self._users = {}

    def save(self, user): self._users[user.id] = user
    def find_by_id(self, id): return self._users.get(id)

# Mock: heavy expectations, breaks when implementation changes
mock_repo = Mock()
mock_repo.save.return_value = None
mock_repo.find_by_id.return_value = User(id=1, email="a@example.com")
# Must assert every call — fragile
